// Angular HttpClient equivalent of fetchJson
import { inject, Injectable } from '@angular/core';
import { HttpClient, HttpErrorResponse } from '@angular/common/http';
import { firstValueFrom } from 'rxjs';

@Injectable({ providedIn: 'root' })
export class ApiService {
  private http = inject(HttpClient);

  async get<T>(url: string): Promise<T> {
    return firstValueFrom(this.http.get<T>(url));
    // HttpClient automatically throws on 4xx/5xx — no response.ok check needed
  }

  async post<T>(url: string, body: unknown): Promise<T> {
    return firstValueFrom(this.http.post<T>(url, body));
  }
}

async function fetchWithRetry<T>(
  url: string,
  init: RequestInit = {},
  maxRetries = 3
): Promise<T> {
  let lastError: Error | undefined;

  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      const response = await fetch(url, init);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      return response.json() as Promise<T>;
    } catch (err) {
      lastError = err as Error;
      if ((err as DOMException).name === 'AbortError') throw err;  // don't retry aborts
      const delay = Math.min(1000 * 2 ** attempt, 8000);
      await new Promise(res => setTimeout(res, delay));
    }
  }
  throw lastError;
}

async function loadDashboard(userId: number) {
  const [user, orders, notifications] = await Promise.all([
    fetchJson<User>(`/api/users/${userId}`),
    fetchJson<Order[]>(`/api/users/${userId}/orders`),
    fetchJson<Notification[]>(`/api/users/${userId}/notifications`),
  ]);
  return { user, orders, notifications };
}

async function streamLargeFile(url: string, onChunk: (chunk: string) => void) {
  const response = await fetch(url);
  if (!response.ok || !response.body) throw new Error('Stream unavailable');

  const reader = response.body.getReader();
  const decoder = new TextDecoder();

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    onChunk(decoder.decode(value, { stream: true }));
  }
}

// Mocking fetch with jasmine in a non-Angular context
describe('fetchJson', () => {
  let fetchSpy: jasmine.Spy;

  beforeEach(() => {
    fetchSpy = spyOn(globalThis, 'fetch');
  });

  it('returns parsed JSON on success', async () => {
    const mockData = { id: 1, name: 'Alice' };
    fetchSpy.and.returnValue(Promise.resolve({
      ok: true,
      json: () => Promise.resolve(mockData),
    } as Response));

    const result = await fetchJson('/api/users/1');
    expect(result).toEqual(mockData);
    expect(fetchSpy).toHaveBeenCalledWith('/api/users/1', undefined);
  });

  it('throws on HTTP error', async () => {
    fetchSpy.and.returnValue(Promise.resolve({
      ok: false,
      status: 404,
      statusText: 'Not Found',
      text: () => Promise.resolve('User not found'),
    } as Response));

    await expectAsync(fetchJson('/api/users/999'))
      .toBeRejectedWithError('404 Not Found: User not found');
  });

  it('rethrows AbortError without retrying', async () => {
    const abortError = new DOMException('Aborted', 'AbortError');
    fetchSpy.and.returnValue(Promise.reject(abortError));

    await expectAsync(fetchWithRetry('/api/data'))
      .toBeRejectedWith(abortError);
    expect(fetchSpy).toHaveBeenCalledTimes(1);   // no retries
  });
});

