// Refresh token on 401
async function authedFetch<T>(url: string, init: RequestInit = {}): Promise<T> {
  let token = await getAccessToken();
  let response = await fetch(url, { ...init, headers: { Authorization: `Bearer ${token}` } });

  if (response.status === 401) {
    token = await refreshToken();
    response = await fetch(url, { ...init, headers: { Authorization: `Bearer ${token}` } });
  }

  if (!response.ok) throw new Error(`HTTP ${response.status}`);
  return response.json() as Promise<T>;
}

// Default — browser decides based on Cache-Control headers
